import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import api from '../api/axiosConfig';
import toast from 'react-hot-toast';
import { UserPlus } from 'lucide-react';

const RegisterPage = () => {
  const [data, setData] = useState({ fullName: '', email: '', password: '' });
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleRegister = async (e) => {
    e.preventDefault();
    if (!data.fullName || !data.email || !data.password) return toast.error('ALL_FIELDS_REQUIRED');

    setLoading(true);
    try {
      await api.post('/auth/register', data);
      toast.success('IDENTITY_INITIALIZED');
      navigate('/login');
    } catch (err) {
      toast.error('REGISTRATION_FAILED');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-6 bg-transparent">
      <div className="w-full max-w-md cyber-card relative overflow-hidden">
        <div className="absolute -top-24 -right-24 w-48 h-48 bg-purple-600/20 blur-[100px]" />

        <div className="text-center mb-10">
          <div className="flex justify-center mb-4 text-purple-400">
            <UserPlus size={42} />
          </div>
          <h1 className="text-3xl font-light tracking-tight text-white mb-2">Create Account</h1>
          <p className="text-white/40 text-[10px] uppercase tracking-[0.25em]">Initialize your node identity</p>
        </div>

        <form onSubmit={handleRegister} className="space-y-4">
          <input
            type="text"
            className="cyber-input"
            placeholder="Full Name"
            value={data.fullName}
            onChange={(e) => setData({ ...data, fullName: e.target.value })}
            required
          />
          <input
            type="email"
            className="cyber-input"
            placeholder="Email Address"
            value={data.email}
            onChange={(e) => setData({ ...data, email: e.target.value })}
            required
          />
          <input
            type="password"
            className="cyber-input"
            placeholder="Password"
            value={data.password}
            onChange={(e) => setData({ ...data, password: e.target.value })}
            required
          />

          <button
            type="submit"
            disabled={loading}
            className={`cyber-btn mt-6 ${loading ? 'opacity-60 cursor-not-allowed' : ''}`}
          >
            {loading ? 'INITIALIZING...' : 'Sign Up'}
          </button>
        </form>

        <p className="text-center mt-10 text-[10px] text-white/30 uppercase tracking-[0.25em]">
          Already registered? <Link to="/login" className="text-purple-400 hover:underline">Sign In</Link>
        </p>
      </div>
    </div>
  );
};

export default RegisterPage;
